sys_ui_policy.script_false:
function onCondition() {
	// DFCT0010374 - nothing should change if false
}

sys_ui_policy.script_true:
function onCondition() {
	// DFCT0010374 "Reviewer Comments" is NOT required on the platform when a task is marked complete from a Review State
	var state = g_scratchpad.currentState;
	var inReview = (state == "14");
	g_form.setMandatory('comments_dt', inReview);
	g_form.setMandatory('response', !inReview);

}
